import json
import time
from dataclasses import dataclass, field
from threading import Lock
from typing import Any

from app.core.config import settings

# Default TTL for model geometry cache: 24 hours
MODEL_CACHE_TTL = 86_400
# Lock TTL must be longer than worst-case CadQuery generation
LOCK_TTL_SECONDS = 120


@dataclass
class LockToken:
    key: str
    backend: str = "memory"


@dataclass
class _CacheEntry:
    value: Any
    expires_at: float | None  # monotonic clock; None = no expiry


class InMemoryCache:
    """
    TTL-aware in-memory cache using monotonic clock.
    Thread-safe. Used for local dev and as fallback for tests.
    NEVER used as fallback when REQUIRE_REDIS_FOR_READY=true.
    """

    def __init__(self) -> None:
        self._data: dict[str, _CacheEntry] = {}
        self._locks: set[str] = set()
        self._mutex = Lock()

    def get(self, key: str) -> Any | None:
        with self._mutex:
            entry = self._data.get(key)
            if entry is None:
                return None
            if entry.expires_at is not None and time.monotonic() > entry.expires_at:
                del self._data[key]
                return None
            return entry.value

    def set(self, key: str, value: Any, ttl_seconds: int | None = MODEL_CACHE_TTL) -> None:
        expires_at = (
            time.monotonic() + ttl_seconds if ttl_seconds is not None else None
        )
        with self._mutex:
            self._data[key] = _CacheEntry(value=value, expires_at=expires_at)

    def acquire_lock(self, key: str, ttl_seconds: int = LOCK_TTL_SECONDS) -> LockToken | None:
        with self._mutex:
            if key in self._locks:
                return None
            self._locks.add(key)
            return LockToken(key=key, backend="memory")

    def release_lock(self, token: LockToken) -> None:
        with self._mutex:
            self._locks.discard(token.key)

    def clear(self) -> None:
        with self._mutex:
            self._data.clear()
            self._locks.clear()

    def is_connected(self) -> bool:
        return False


class RedisCache:
    """
    Redis-backed cache with InMemoryCache fallback for local dev only.
    When REQUIRE_REDIS_FOR_READY=true, fallback is disabled — errors propagate.
    """

    def __init__(self, url: str, fallback: InMemoryCache) -> None:
        self.fallback = fallback
        self._strict = settings.require_redis_for_ready
        self.client = None
        try:
            import redis
            client = redis.Redis.from_url(url, decode_responses=False,
                                          socket_connect_timeout=3,
                                          socket_timeout=3)
            client.ping()
            self.client = client
        except Exception as exc:
            if self._strict:
                raise RuntimeError(
                    f"Redis connection failed and REQUIRE_REDIS_FOR_READY=true. "
                    f"Cannot fall back to in-memory cache in production. "
                    f"Error: {exc}"
                ) from exc
            # local dev: fall back silently

    def get(self, key: str) -> Any | None:
        if self.client is None:
            return self.fallback.get(key)
        raw = self.client.get(key)
        return json.loads(raw) if raw else None

    def set(self, key: str, value: Any, ttl_seconds: int | None = MODEL_CACHE_TTL) -> None:
        if self.client is None:
            return self.fallback.set(key, value, ttl_seconds)
        self.client.set(key, json.dumps(value), ex=ttl_seconds)

    def acquire_lock(self, key: str, ttl_seconds: int = LOCK_TTL_SECONDS) -> LockToken | None:
        if self.client is None:
            return self.fallback.acquire_lock(key, ttl_seconds)
        ok = self.client.set(key, "1", nx=True, ex=ttl_seconds)
        return LockToken(key=key, backend="redis") if ok else None

    def release_lock(self, token: LockToken) -> None:
        if self.client is None or token.backend == "memory":
            return self.fallback.release_lock(token)
        self.client.delete(token.key)

    def clear(self) -> None:
        if self.client is None:
            return self.fallback.clear()

    def is_connected(self) -> bool:
        if self.client is None:
            return False
        try:
            return bool(self.client.ping())
        except Exception:
            return False


def _build_cache():
    mem = InMemoryCache()
    if settings.redis_url:
        return RedisCache(settings.redis_url, mem)
    return mem


cache = _build_cache()

