import logging from app.workers.tasks import dispatch_generation_job, get_celery_app, reset_celery_for_testing from app.core.config import settings
def test_dispatch_without_redis_logs_warning_not_raises(caplog): original = settings.redis_url settings.redis_url = None reset_celery_for_testing() try: with caplog.at_level(logging.WARNING, logger="app.workers.tasks"): result = dispatch_generation_job("preview_fast", "test-job-123") assert result is False assert "REDIS_URL not configured" in caplog.text finally: settings.redis_url = original reset_celery_for_testing()
def test_get_celery_app_raises_without_redis(): original = settings.redis_url settings.redis_url = None reset_celery_for_testing() try: with pytest.raises(RuntimeError, match="REDIS_URL is required"): get_celery_app() finally: settings.redis_url = original reset_celery_for_testing()
